import java.util.PriorityQueue;
import java.util.Scanner;
import java.util.Comparator;

public class Main {
    static class Flight implements Comparable<Flight> {
        int city1, time1, city2, time2;
        public Flight(int city1, int time1, int city2, int time2) {
            this.city1 = city1;
            this.time1 = time1;
            this.city2 = city2;
            this.time2 = time2;
        }
        @Override
        public int compareTo(Flight o) {
            if (this.city1 != o.city1) return this.city1 - o.city1;
            return this.time1 - o.time1;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            Flight[] flights = new Flight[N];
            for (int i = 0; i < N; i++) {
                flights[i] = new Flight(sc.nextInt(), sc.nextInt(), sc.nextInt(), sc.nextInt());
            }
            int startCity = sc.nextInt();
            int startTime = sc.nextInt();
            int endCity = sc.nextInt();
            int endTime = sc.nextInt();
            Arrays.sort(flights);
            int count = 0;
            PriorityQueue<Flight> pq = new PriorityQueue<>((o1, o2) -> o1.time1 - o2.time1);
            pq.add(new Flight(startCity, startTime, -1, -1));
            while (!pq.isEmpty()) {
                Flight current = pq.poll();
                for (int i = 0; i < N; i++) {
                    if (flights[i].city1 == current.city1 && flights[i].time1 >= current.time1) {
                        count++;
                        if (flights[i].city2 == endCity && flights[i].time2 <= endTime) {
                            System.out.println("Yes " + count);
                            break;
                        }
                        pq.add(new Flight(flights[i].city2, flights[i].time2, -1, -1));
                    }
                }
            }
            if (pq.isEmpty()) System.out.println("No");
        }
    }
}

